const config = $('⚙️ CONFIG GLOBAL1').first().json;
const termosIgnorados = (config.TERMOS_IGNORADOS || '').split(',').map(t => t.trim().toLowerCase());
let lista = [];
if (items.length > 0 && Array.isArray(items[0].json)) { lista = items[0].json; }
else { lista = items.map(i => i.json); }
const offline = lista.filter(instancia => {
    const st = (instancia.connectionStatus || instancia.status || '').toLowerCase();
    if (st === 'connected' || st === 'open') return false;
    const nome = (instancia.name || '').toLowerCase();
    const perfil = (instancia.profileName || '').toLowerCase();
    return !termosIgnorados.some(t => nome.includes(t) || perfil.includes(t));
});
if (offline.length === 0) return [];
const fmt = (raw) => {
    let n = (raw || '').toString().replace(/\D/g,'');
    if (n.startsWith('55') && n.length >= 12) {
        const ddd = n.slice(2,4); const num = n.slice(4);
        return `+55 ${ddd} ${num.slice(0,-4)}-${num.slice(-4)}`;
    }
    return raw || 'Não identificado';
};
return offline.map(i => ({ json: {
    chip_name: i.name || 'Sem Nome',
    phone_raw: i.owner || i.ownerJid || '',
    phone_fmt: fmt(i.owner || i.ownerJid || ''),
    status: i.connectionStatus || i.status || 'disconnected',
    token: i.token || ''
}}));

const item = $input.first();
const qr = (item.json?.instance?.qrcode || item.json?.qrcode || item.json?.base64 || '').replace(/^data:image\/png;base64,/, '');
const initNode = $('📡 API: Criar1').first();
const token = initNode?.json?.instance?.token || initNode?.json?.hash || '';
const webhookNode = $('🌐 Webhook: Criar1').first();
const nome = webhookNode?.json?.body?.instanceName || 'Nova Instancia';

return [{ json: { success: true, instanceName: nome, token: token, qrCodeBase64: qr, message: `Instância '${nome}' criada! Escaneie o QR.` } }];

const item = $input.first();
const st = item.json?.instance?.state || item.json?.state || item.json?.status || '';
if (st === 'open' || st === 'connected' || st === 'connecting') {
    return [{ json: { success: true, connected: true, qrCodeBase64: '', message: 'Instância já está conectada.' } }];
}
const qr = (item.json?.instance?.qrcode || item.json?.qrcode || item.json?.base64 || '').replace(/^data:image\/png;base64,/,'');
return [{ json: { success: true, qrCodeBase64: qr, message: 'QR gerado. Escaneie para reconectar.' } }];

